//! Dynamic-`import()` lowering helper.
//!
//! TypeScript's `await import('./mod')` is a syntactic call_expression whose
//! callee is the `import` keyword (not an identifier). The default
//! `ts_node_to_ir` path lowers an unrecognized callee to
//! `{kind:"raw", text:"import"}`, which gnexec's `eval_ir` "raw" arm cannot
//! resolve (the bare `import` token reparses as an `import_statement`, not an
//! expression — hence the observed
//! `eval_ir: 'raw' IR fallback to source-text reparse failed for 'import'`).
//!
//! Real-world TS uses dynamic import as a *fast-path probe* wrapped in
//! try/catch:
//!
//! ```ts
//! try {
//!   const { fooWASM } = await import('./mod');
//!   return await fooWASM(...);
//! } catch (_) {
//!   // pure-TS fallback the orchestration walker CAN evaluate
//! }
//! ```
//!
//! The minimum viable fix: lower a dynamic-import call to a `kind:"throw"`
//! IR carrying a sentinel literal. gnexec's Try-frame then routes execution
//! into the catch branch, which is the path the author already wrote for the
//! "WASM unavailable" case. No WASM resolution, no module loader, no host
//! plumbing — the catch branch *is* the fallback, by design.
//!
//! Sentinel value: `"dynamic_import_unsupported"`. Catch handlers that don't
//! inspect the error (the common pattern shown above) ignore it; ones that do
//! see a deterministic string they can pattern-match.

use serde_json::{json, Value};
use tree_sitter::Node;

/// If `node` is a `call_expression` whose callee is the `import` keyword
/// (i.e. a dynamic `import('…')` call), return throw-IR that gnexec can
/// evaluate. Otherwise return `None` so the caller falls through to the
/// default `call_expression` lowering.
///
/// The returned IR shape is:
///
/// ```json
/// { "kind": "throw",
///   "error": { "kind": "literal", "value": "dynamic_import_unsupported" } }
/// ```
///
/// Intended to be called from `typescript.rs::ts_node_to_ir` at the top of
/// the `"call_expression"` arm:
///
/// ```ignore
/// "call_expression" => {
///     if let Some(ir) = import_helper::lower_dynamic_import_call(node, source) {
///         return ir;
///     }
///     // … existing callee/args lowering …
/// }
/// ```
///
/// `_source` is accepted (and currently unused) to keep the signature
/// symmetric with the other `lower_*` helpers in this module family and to
/// leave room for capturing the import specifier as a debug field later.
pub(crate) fn lower_dynamic_import_call(node: &Node, _source: &str) -> Option<Value> {
    if node.kind() != "call_expression" {
        return None;
    }
    let func = node.child_by_field_name("function")?;
    // tree-sitter-typescript represents the `import` keyword in a dynamic
    // import as a node whose `kind()` is literally `"import"` (anonymous
    // keyword node). Anything else — `identifier`, `member_expression`,
    // `parenthesized_expression`, etc. — is a regular call and should fall
    // through to the default lowering.
    if func.kind() != "import" {
        return None;
    }
    Some(json!({
        "kind": "throw",
        "error": {
            "kind": "literal",
            "value": "dynamic_import_unsupported"
        }
    }))
}

/// Companion predicate for gnexec-side detection (used by the alternate
/// patch path in `bin/gnexec.rs::eval_ir_call`). Returns `true` when the
/// callee IR is `{kind:"raw", text:"import"}`. Kept here so both fix sites
/// share a single source of truth for the sentinel shape.
#[allow(dead_code)]
pub(crate) fn is_dynamic_import_callee(callee_ir: &Value) -> bool {
    callee_ir.get("kind").and_then(Value::as_str) == Some("raw")
        && callee_ir.get("text").and_then(Value::as_str) == Some("import")
}
